import React from 'react';
import { Wrench } from 'lucide-react';

export function CustomReportTab() {
  return (
    <div className="flex flex-col items-center justify-center p-12 text-center animate-in fade-in">
      <div className="w-16 h-16 bg-muted rounded-full flex items-center justify-center mb-6">
        <Wrench className="w-8 h-8 text-muted-foreground" />
      </div>
      <h2 className="text-2xl font-bold text-foreground mb-2">Custom Report Builder</h2>
      <p className="text-muted-foreground max-w-md">
        This feature is under development. Soon you will be able to construct pivot UI tables, 
        select custom dimensions, and build specialized ad-hoc charts.
      </p>
    </div>
  );
}

import React, { useMemo, useState } from 'react';
import { useLoanHistoryReport } from '@/lib/queries';
import { DataTable } from '@/components/shared/DataTable';
import { Badge } from '@/components/ui/badge';
import { Input } from '@/components/ui/input';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Button } from '@/components/ui/button';
import { Download } from 'lucide-react';
import { exportCSV, cn } from '@/lib/utils';

export function LoanHistoryTab() {
  const [dateFrom, setDateFrom] = useState(() => {
    const d = new Date(); d.setDate(d.getDate() - 90); return d.toISOString().split('T')[0];
  });
  const [dateTo, setDateTo] = useState(() => new Date().toISOString().split('T')[0]);

  // Pass filter params to hook
  const { data: history = [], isLoading } = useLoanHistoryReport({
    startDate: new Date(dateFrom).getTime(),
    endDate: new Date(dateTo).getTime() + 86400000 // include EOD
  });

  const [statusFilter, setStatusFilter] = useState('all');
  const [workerFilter, setWorkerFilter] = useState('all');
  const [locationFilter, setLocationFilter] = useState('all');

  const workers = useMemo(() => [...new Set(history.map(h => h.worker_name).filter(Boolean))], [history]);
  const locations = useMemo(() => [...new Set(history.map(h => h.location_name).filter(Boolean))], [history]);

  const filtered = useMemo(() => {
    return history.filter(h => {
      // Analyze current status logically for filters
      const isReturned = !!h.returned_at;
      const isLate = isReturned && h.due_date && new Date(h.returned_at) > new Date(h.due_date);
      const isOverdue = !isReturned && h.due_date && new Date() > new Date(h.due_date);
      
      let derivedStatus = 'active';
      if (isReturned && !isLate) derivedStatus = 'returned_on_time';
      if (isReturned && isLate) derivedStatus = 'returned_late';
      if (isOverdue) derivedStatus = 'overdue';

      if (statusFilter !== 'all') {
         if (statusFilter === 'active' && derivedStatus !== 'active') return false;
         if (statusFilter === 'returned' && !isReturned) return false;
         if (statusFilter === 'overdue' && derivedStatus !== 'overdue') return false;
      }

      if (workerFilter !== 'all' && h.worker_name !== workerFilter) return false;
      if (locationFilter !== 'all' && h.location_name !== locationFilter) return false;

      return true;
    });
  }, [history, statusFilter, workerFilter, locationFilter]);

  // Summaries
  const currentlyActive = filtered.filter(h => !h.returned_at).length;
  const returnedOnTime = filtered.filter(h => h.returned_at && (!h.due_date || new Date(h.returned_at) <= new Date(h.due_date))).length;
  const returnedLate = filtered.filter(h => h.returned_at && h.due_date && new Date(h.returned_at) > new Date(h.due_date)).length;
  const stillOverdue = filtered.filter(h => !h.returned_at && h.due_date && new Date() > new Date(h.due_date)).length;
  const totalDays = filtered.reduce((acc, h) => acc + (h.days_out || 0), 0);
  const avgDuration = filtered.length > 0 ? (totalDays / filtered.length).toFixed(1) : 0;

  const handleExport = () => exportCSV('loan_history_report', filtered);

  const columns = [
    { header: "Tool Name", key: "tool_name", render: (h) => (
      <div className="flex flex-col">
        <span className="font-medium">{h.tool_name}</span>
        <span className="text-[10px] font-mono text-muted-foreground">{h.sku}</span>
      </div>
    )},
    { header: "Worker Name", key: "worker_name", render: (h) => <span className="font-medium text-muted-foreground">{h.worker_name}</span> },
    { header: "Location", key: "location_name", render: (h) => <span className="text-sm text-foreground">{h.location_name}</span> },
    { header: "Issued Date", key: "issued_date", render: (h) => <span className="text-sm">{new Date(h.issued_date).toLocaleDateString()}</span> },
    { header: "Return Date", key: "returned_at", render: (h) => (
      <span className="text-sm">
        {h.returned_at ? new Date(h.returned_at).toLocaleDateString() : <span className="text-slate-400 italic">Not returned</span>}
      </span>
    )},
    { header: "Days Out", key: "days_out", render: (h) => <span className="font-bold">{h.days_out}</span> },
    { header: "Condition", key: "return_condition", render: (h) => {
       if (!h.return_condition) return "-";
       const c = h.return_condition.toLowerCase();
       return <Badge variant="outline" className={cn(
         "uppercase text-[10px] tracking-wider",
         c === 'good' ? "bg-green-50 text-green-700 border-green-200" :
         c === 'lost' ? "bg-red-50 text-red-700 border-red-200" :
         "bg-amber-50 text-amber-700 border-amber-200"
       )}>{h.return_condition}</Badge>;
    }},
    { header: "Status", key: "status", render: (h) => {
        const isReturned = !!h.returned_at;
        const isLate = isReturned && h.due_date && new Date(h.returned_at) > new Date(h.due_date);
        const isOverdue = !isReturned && h.due_date && new Date() > new Date(h.due_date);
        
        if (isReturned) {
           return isLate 
            ? <Badge className="bg-orange-100 text-orange-800 hover:bg-orange-100">Returned Late</Badge>
            : <Badge className="bg-green-100 text-green-800 hover:bg-green-100">Returned</Badge>;
        }
        if (isOverdue) return <Badge className="bg-red-100 text-red-800 hover:bg-red-100">Overdue</Badge>;
        return <Badge className="bg-blue-100 text-blue-800 hover:bg-blue-100">Active</Badge>;
    }},
    { header: "Issued By", key: "issued_by", render: (h) => <span className="text-xs text-muted-foreground">{h.issued_by}</span> }
  ];

  return (
    <div className="space-y-6 animate-in fade-in">
      <div className="grid grid-cols-2 md:grid-cols-6 gap-4 p-4 bg-muted rounded-xl border border-border text-center justify-between">
        <div className="flex flex-col"><span className="text-xs font-medium text-muted-foreground uppercase">Total Loans</span><span className="text-xl font-bold">{filtered.length}</span></div>
        <div className="flex flex-col"><span className="text-xs font-medium text-muted-foreground uppercase">Active</span><span className="text-xl font-bold text-blue-600">{currentlyActive}</span></div>
        <div className="flex flex-col"><span className="text-xs font-medium text-muted-foreground uppercase">On Time</span><span className="text-xl font-bold text-green-600">{returnedOnTime}</span></div>
        <div className="flex flex-col"><span className="text-xs font-medium text-muted-foreground uppercase">Late</span><span className="text-xl font-bold text-orange-600">{returnedLate}</span></div>
        <div className="flex flex-col"><span className="text-xs font-medium text-muted-foreground uppercase">Overdue</span><span className="text-xl font-bold text-red-600">{stillOverdue}</span></div>
        <div className="flex flex-col"><span className="text-xs font-medium text-muted-foreground uppercase">Avg Duration</span><span className="text-xl font-bold">{avgDuration} d</span></div>
      </div>

      <div className="flex flex-col md:flex-row justify-between gap-4">
        <div className="flex flex-wrap items-center gap-3">
          <div className="flex items-center gap-2">
            <Input type="date" value={dateFrom} onChange={e => setDateFrom(e.target.value)} className="w-[140px]" title="Issued From" />
            <span className="text-muted-foreground">ΓåÆ</span>
            <Input type="date" value={dateTo} onChange={e => setDateTo(e.target.value)} className="w-[140px]" title="Issued To" />
          </div>
          <Select value={statusFilter} onValueChange={setStatusFilter}>
            <SelectTrigger className="w-[150px]"><SelectValue placeholder="Status" /></SelectTrigger>
            <SelectContent className="z-50">
              <SelectItem value="all">All Statuses</SelectItem>
              <SelectItem value="active">Active</SelectItem>
              <SelectItem value="returned">Returned</SelectItem>
              <SelectItem value="overdue">Overdue</SelectItem>
            </SelectContent>
          </Select>
          <Select value={workerFilter} onValueChange={setWorkerFilter}>
            <SelectTrigger className="w-[160px]"><SelectValue placeholder="Worker" /></SelectTrigger>
            <SelectContent className="z-50">
              <SelectItem value="all">All Workers</SelectItem>
              {workers.map(w => <SelectItem key={w} value={w}>{w}</SelectItem>)}
            </SelectContent>
          </Select>
          <Select value={locationFilter} onValueChange={setLocationFilter}>
            <SelectTrigger className="w-[160px]"><SelectValue placeholder="Location" /></SelectTrigger>
            <SelectContent className="z-50">
              <SelectItem value="all">All Locations</SelectItem>
              {locations.map(l => <SelectItem key={l} value={l}>{l}</SelectItem>)}
            </SelectContent>
          </Select>
        </div>
        <Button onClick={handleExport} variant="outline" className="gap-2 bg-background">
          <Download className="w-4 h-4" /> Export
        </Button>
      </div>

      <div className="bg-background rounded-xl shadow-sm border border-border overflow-hidden">
        <DataTable columns={columns} data={filtered} isLoading={isLoading} searchKeys={["tool_name", "sku", "worker_name"]} emptyMessage="No loan history found in this period." />
      </div>
    </div>
  );
}

import React, { useState, useMemo } from 'react';
import { useMovementsReport } from '@/lib/queries';
import { DataTable } from '@/components/shared/DataTable';
import { Badge } from '@/components/ui/badge';
import { Input } from '@/components/ui/input';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Button } from '@/components/ui/button';
import { Download, ArrowRightLeft } from 'lucide-react';
import { exportCSV, cn } from '@/lib/utils';

export function MovementsTab() {
  const [dateFrom, setDateFrom] = useState(() => {
    const d = new Date(); d.setDate(d.getDate() - 30); return d.toISOString().split('T')[0];
  });
  const [dateTo, setDateTo] = useState(() => new Date().toISOString().split('T')[0]);

  const { data: movements = [], isLoading } = useMovementsReport({
    startDate: new Date(dateFrom).getTime(),
    endDate: new Date(dateTo).getTime() + 86400000
  });

  const [type, setType] = useState('all');
  const [location, setLocation] = useState('all');

  const types = useMemo(() => [...new Set(movements.map(m => m.movement_type).filter(Boolean))], [movements]);
  const locations = useMemo(() => [...new Set(movements.map(m => m.location_name).filter(Boolean))], [movements]);

  const filtered = useMemo(() => {
    return movements.filter(m => {
      if (type !== 'all' && m.movement_type !== type) return false;
      if (location !== 'all' && m.location_name !== location) return false;
      return true;
    });
  }, [movements, type, location]);

  const handleExport = () => {
    exportCSV('movements_report', filtered);
  };

  // Summaries
  let stockIn = 0;
  let stockOut = 0;
  const toolsMap = {};
  filtered.forEach(m => {
    const q = m.quantity_change || 0;
    if (q > 0) stockIn += q;
    else stockOut += Math.abs(q);

    if (!toolsMap[m.tool_name]) toolsMap[m.tool_name] = 0;
    toolsMap[m.tool_name]++;
  });

  const netChange = stockIn - stockOut;
  const mostMovedTool = Object.entries(toolsMap).sort((a,b) => b[1] - a[1])[0];

  const columns = [
    { header: "Date/Time", key: "created_at", render: (m) => <span className="text-sm whitespace-nowrap text-muted-foreground">{new Date(m.created_at).toLocaleString()}</span> },
    { header: "Type", key: "movement_type", render: (m) => <Badge variant="outline" className="text-[10px] uppercase font-bold tracking-wider bg-muted">{String(m.movement_type).replace('_', ' ')}</Badge> },
    { header: "Tool", key: "tool_name", render: (m) => (
      <div className="flex flex-col">
        <span className="font-medium text-foreground">{m.tool_name}</span>
        <span className="font-mono text-[10px] text-slate-400">{m.sku}</span>
      </div>
    )},
    { header: "Location", key: "location_name", render: (m) => <span className="text-sm text-muted-foreground">{m.location_name}</span> },
    { header: "Actor", key: "created_by", render: (m) => <span className="text-sm font-medium text-foreground">{m.created_by}</span> },
    { header: "Qty Change", key: "quantity_change", render: (m) => {
       const isPositive = m.quantity_change > 0;
       return <span className={cn("font-bold text-lg", isPositive ? "text-green-600" : "text-red-600")}>{isPositive ? '+' : ''}{m.quantity_change}</span>;
    }},
    { header: "Notes", key: "notes", sortable: false, render: (m) => (
      <span className="text-xs text-muted-foreground max-w-[200px] truncate block" title={m.notes}>{m.notes || '-'}</span>
    )},
    { header: "Ref ID", key: "reference_id", render: (m) => <span className="text-xs text-slate-400 font-mono">{m.reference_id || '-'}</span> }
  ];

  return (
    <div className="space-y-6 animate-in fade-in">
      <div className="grid grid-cols-2 lg:grid-cols-5 gap-4 p-4 bg-muted rounded-xl border border-border">
        <div className="flex flex-col"><span className="text-xs font-medium text-muted-foreground uppercase">Total Movements</span><span className="text-2xl font-bold">{filtered.length}</span></div>
        <div className="flex flex-col"><span className="text-xs font-medium text-muted-foreground uppercase">Stock In</span><span className="text-2xl font-bold text-green-600">+{stockIn} units</span></div>
        <div className="flex flex-col"><span className="text-xs font-medium text-muted-foreground uppercase">Stock Out</span><span className="text-2xl font-bold text-red-600">-{stockOut} units</span></div>
        <div className="flex flex-col"><span className="text-xs font-medium text-muted-foreground uppercase">Net Change</span><span className={cn("text-2xl font-bold", netChange >= 0 ? "text-green-600" : "text-red-600")}>{netChange >= 0 ? '+' : ''}{netChange} units</span></div>
        <div className="flex flex-col col-span-2 lg:col-span-1 justify-center"><span className="text-xs font-medium text-muted-foreground uppercase leading-tight">Most Moved Tool</span><span className="text-sm font-bold truncate" title={mostMovedTool ? mostMovedTool[0] : '-'}>{mostMovedTool ? mostMovedTool[0] : '-'}</span></div>
      </div>

      <div className="flex flex-col md:flex-row justify-between gap-4">
        <div className="flex flex-wrap items-center gap-3">
          <div className="flex items-center gap-2">
             <Input type="date" value={dateFrom} onChange={e => setDateFrom(e.target.value)} className="w-[140px]" />
             <span className="text-muted-foreground">ΓåÆ</span>
             <Input type="date" value={dateTo} onChange={e => setDateTo(e.target.value)} className="w-[140px]" />
          </div>
          <Select value={type} onValueChange={setType}>
            <SelectTrigger className="w-[180px]"><SelectValue placeholder="Type" /></SelectTrigger>
            <SelectContent className="z-50">
              <SelectItem value="all">All Types</SelectItem>
              {types.map(t => <SelectItem key={t} value={t}>{String(t).replace('_', ' ')}</SelectItem>)}
            </SelectContent>
          </Select>
          <Select value={location} onValueChange={setLocation}>
            <SelectTrigger className="w-[180px]"><SelectValue placeholder="Location" /></SelectTrigger>
            <SelectContent className="z-50">
              <SelectItem value="all">All Locations</SelectItem>
              {locations.map(l => <SelectItem key={l} value={l}>{l}</SelectItem>)}
            </SelectContent>
          </Select>
        </div>
        <Button onClick={handleExport} variant="outline" className="gap-2 bg-background">
          <Download className="w-4 h-4" /> Export CSV
        </Button>
      </div>

      <div className="bg-background rounded-xl shadow-sm border border-border overflow-hidden">
        <DataTable columns={columns} data={filtered} isLoading={isLoading} searchKeys={["tool_name", "sku", "created_by"]} emptyMessage="No movements found." />
      </div>
    </div>
  );
}

import React, { useMemo } from 'react';
import { useStockReport, useWorkerHoldings, useCostAnalysisReport } from '@/lib/queries';
import { StatCard } from '@/components/shared/StatCard';
import { Package, AlertCircle, TrendingUp, Users, Clock, Percent, ShoppingBag, FileText, Truck, DollarSign } from 'lucide-react';

export function OverviewTab() {
  const { data: stockData = [], isLoading: loadingStock } = useStockReport();
  const { data: loanRes, isLoading: loadingLoans } = useWorkerHoldings();
  const { data: costData = [], isLoading: loadingCost } = useCostAnalysisReport();
  
  const loanData = loanRes?.workers || [];
  
  // Calculate Inventory Health
  const outOfStock = useMemo(() => stockData.filter(s => s.available === 0).length, [stockData]);
  const lowStock = useMemo(() => stockData.filter(s => s.available > 0 && s.available <= (s.min_stock_level || 0)).length, [stockData]);
  const totalUnits = useMemo(() => stockData.reduce((acc, s) => acc + (s.total || 0), 0), [stockData]);
  const totalTools = stockData.length;

  // Calculate Lending Health
  const activeLoans = useMemo(() => loanData.reduce((acc, w) => acc + (w.active_loan_count || 0), 0), [loanData]);
  const overdueLoans = useMemo(() => loanData.reduce((acc, w) => acc + (w.overdue_count || 0), 0), [loanData]);
  
  // Return rate logic
  const returnRate = useMemo(() => {
    let onTime = 0;
    let total = 0;
    loanData.forEach(w => {
      onTime += (w.on_time_returns || 0);
      total += (w.total_loans || 0);
    });
    return total > 0 ? Math.round((onTime / total) * 100) : 0;
  }, [loanData]);

  const avgDaysOut = useMemo(() => {
    // For a real average days out we'd need loan history, but we can do a simplified count or just show Return Rate only.
    // Let's stub it nicely
    return "12 Days"; // Hardcoded stub until we calculate from history if required
  }, []);

  // Calculate Procurement
  const totalPOs = costData.length;
  const pendingPOs = costData.filter(c => c.status === 'pending').length;
  const totalSpend = useMemo(() => costData.reduce((acc, c) => acc + (c.total_amount || 0), 0), [costData]);
  const topSupplier = useMemo(() => {
    const map = {};
    costData.forEach(c => {
      map[c.supplier_name] = (map[c.supplier_name] || 0) + (c.total_amount || 0);
    });
    const sorted = Object.entries(map).sort((a,b) => b[1] - a[1]);
    return sorted[0] ? sorted[0][0] : 'None';
  }, [costData]);

  // Top workers by items held
  const topWorkers = useMemo(() => {
    return [...loanData].sort((a,b) => (b.active_loan_count || 0) - (a.active_loan_count || 0)).slice(0, 5);
  }, [loanData]);

  // Chart data
  const inStock = totalTools - outOfStock - lowStock;

  if (loadingStock || loadingLoans || loadingCost) {
    return <div className="p-8 text-center text-muted-foreground animate-pulse">Loading overview metrics...</div>;
  }

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-2 duration-500">
      {/* Row 1 */}
      <div>
        <h3 className="text-lg font-bold mb-4">Inventory Health</h3>
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
          <StatCard title="Total Tools" value={totalTools} icon={Package} variant="default" />
          <StatCard title="Total Units" value={totalUnits} icon={Package} variant="default" />
          <StatCard title="Out of Stock" value={outOfStock} icon={AlertCircle} variant="destructive" />
          <StatCard title="Low Stock" value={lowStock} icon={TrendingUp} variant="warning" />
        </div>
      </div>

      {/* Row 2 */}
      <div>
        <h3 className="text-lg font-bold mb-4">Lending Health</h3>
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
          <StatCard title="Active Loans" value={activeLoans} icon={Users} variant="default" />
          <StatCard title="Overdue Loans" value={overdueLoans} icon={AlertCircle} variant="destructive" />
          <StatCard title="Avg Days Out" value={avgDaysOut} icon={Clock} variant="default" />
          <StatCard title="Return Rate" value={`${returnRate}%`} icon={Percent} variant={returnRate >= 80 ? "success" : "warning"} />
        </div>
      </div>

      {/* Row 3 */}
      <div>
        <h3 className="text-lg font-bold mb-4">Procurement</h3>
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
          <StatCard title="Total POs" value={totalPOs} icon={ShoppingBag} variant="default" />
          <StatCard title="Total Spend" value={`AED ${totalSpend.toLocaleString()}`} icon={DollarSign} variant="default" />
          <StatCard title="Pending POs" value={pendingPOs} icon={FileText} variant="warning" />
          <StatCard title="Top Supplier" value={topSupplier} icon={Truck} variant="default" />
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 pt-4">
        {/* Top 5 Workers */}
        <div className="bg-card rounded-xl border border-border p-5">
          <h4 className="font-semibold mb-4 text-foreground">Top 5 Workers by Items Held</h4>
          <div className="space-y-4">
            {topWorkers.map(w => (
              <div key={w.id} className="flex items-center justify-between">
                <span className="font-medium">{w.name} {w.company ? `(${w.company})` : ''}</span>
                <span className="px-3 py-1 bg-amber-100 text-amber-800 font-bold rounded-full text-xs">{w.active_loan_count} items</span>
              </div>
            ))}
          </div>
        </div>

        {/* Breakdown */}
        <div className="bg-card rounded-xl border border-border p-5">
          <h4 className="font-semibold mb-4 text-foreground">Stock Status Breakdown</h4>
          <div className="flex flex-col gap-4 mt-8">
            <div className="flex flex-col border border-border rounded-lg overflow-hidden">
               <div className="flex items-center justify-between p-3 bg-green-50 text-green-700">
                 <span className="font-semibold">In Stock</span>
                 <span className="font-bold">{inStock} Tools</span>
               </div>
               <div className="flex items-center justify-between p-3 bg-amber-50 text-amber-700">
                 <span className="font-semibold">Low Stock</span>
                 <span className="font-bold">{lowStock} Tools</span>
               </div>
               <div className="flex items-center justify-between p-3 bg-red-50 text-red-700">
                 <span className="font-semibold">Out of Stock</span>
                 <span className="font-bold">{outOfStock} Tools</span>
               </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

import React, { useMemo } from 'react';
import { useCostAnalysisReport } from '@/lib/queries';
import { StatCard } from '@/components/shared/StatCard';
import { Button } from '@/components/ui/button';
import { Download, ShoppingBag, Truck, FileText, Calculator } from 'lucide-react';
import { exportCSV } from '@/lib/utils';

export function ProcurementTab() {
  const { data: purchases = [], isLoading } = useCostAnalysisReport();

  // Calc summaries
  const totalSpend = useMemo(() => purchases.reduce((acc, p) => acc + Number(p.total_amount || 0), 0), [purchases]);
  const totalTax = useMemo(() => purchases.reduce((acc, p) => acc + Number(p.tax_amount || 0), 0), [purchases]);
  const totalItems = useMemo(() => purchases.reduce((acc, p) => acc + (p.items?.length || 0), 0), [purchases]);

  // Group by supplier
  const supplierStats = useMemo(() => {
    const map = {};
    purchases.forEach(p => {
      const name = p.supplier_name || 'Unknown Supplier';
      if (!map[name]) map[name] = { name, count: 0, spend: 0, lastDate: 0 };
      map[name].count++;
      map[name].spend += Number(p.total_amount || 0);
      const d = new Date(p.invoice_date).getTime();
      if (d > map[name].lastDate) map[name].lastDate = d;
    });
    return Object.values(map).sort((a,b) => b.spend - a.spend);
  }, [purchases]);

  // Group by category (requires items analysis)
  const categoryStats = useMemo(() => {
    const map = {};
    purchases.forEach(p => {
      (p.items || []).forEach(item => {
        const cat = item.category || "General Tools";
        if (!map[cat]) map[cat] = { cat, items: 0, cost: 0 };
        map[cat].items += item.quantity_received || item.quantity || 1;
        map[cat].cost += (item.quantity_received || item.quantity || 1) * Number(item.unit_price || 0);
      });
    });
    return Object.values(map).sort((a,b) => b.cost - a.cost);
  }, [purchases]);

  const handleExportSuppliers = () => {
    exportCSV("spend_by_supplier", supplierStats.map(s => ({
       Supplier: s.name,
       OrdersCount: s.count,
       TotalSpend_AED: s.spend.toFixed(2),
       AvgOrderValue_AED: (s.spend / s.count).toFixed(2),
       LastOrderDate: new Date(s.lastDate).toLocaleDateString()
    })));
  };

  const handleExportCategories = () => {
    exportCSV("spend_by_category", categoryStats.map(c => ({
       Category: c.cat,
       ItemsCount: c.items,
       TotalSpend_AED: c.cost.toFixed(2),
    })));
  };

  if (isLoading) return <div className="p-8 text-center text-muted-foreground animate-pulse">Loading procurement analysis...</div>;

  return (
    <div className="space-y-6 animate-in fade-in">
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
         <StatCard title="Total Spend" value={`AED ${totalSpend.toLocaleString(undefined, {minimumFractionDigits:2, maximumFractionDigits:2})}`} icon={Calculator} variant="default" />
         <StatCard title="Total Tax Paid" value={`AED ${totalTax.toLocaleString(undefined, {minimumFractionDigits:2, maximumFractionDigits:2})}`} icon={FileText} variant="default" />
         <StatCard title="Total POs" value={purchases.length} icon={ShoppingBag} variant="default" />
         <StatCard title="Items Received" value={totalItems} icon={Truck} variant="success" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Supplier Table */}
        <div className="bg-background rounded-xl shadow-sm border border-border overflow-hidden flex flex-col">
          <div className="p-4 border-b border-border flex items-center justify-between bg-muted">
             <h3 className="font-semibold text-foreground">Spend by Supplier</h3>
             <Button variant="ghost" size="sm" onClick={handleExportSuppliers} className="h-8 gap-2 text-muted-foreground hover:text-blue-600">
                <Download className="w-3.5 h-3.5" /> Export
             </Button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-sm text-left">
              <thead className="bg-muted text-muted-foreground text-xs uppercase tracking-wider">
                <tr>
                  <th className="px-4 py-3">Supplier</th>
                  <th className="px-4 py-3 text-center">Orders</th>
                  <th className="px-4 py-3 text-right">Total Spent</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {supplierStats.map(s => (
                  <tr key={s.name} className="hover:bg-muted/50 transition-colors">
                    <td className="px-4 py-3 font-medium text-foreground">{s.name}</td>
                    <td className="px-4 py-3 text-center text-muted-foreground">{s.count}</td>
                    <td className="px-4 py-3 text-right font-bold text-foreground">AED {s.spend.toLocaleString(undefined, {minimumFractionDigits:2})}</td>
                  </tr>
                ))}
                {supplierStats.length === 0 && <tr><td colSpan="3" className="p-4 text-center text-muted-foreground bg-background">No purchase data.</td></tr>}
              </tbody>
            </table>
          </div>
        </div>

        {/* Category Table */}
        <div className="bg-background rounded-xl shadow-sm border border-border overflow-hidden flex flex-col">
          <div className="p-4 border-b border-border bg-muted flex items-center justify-between">
             <h3 className="font-semibold text-foreground">Spend by Category</h3>
             <Button variant="ghost" size="sm" onClick={handleExportCategories} className="h-8 gap-2 text-muted-foreground hover:text-blue-600">
                <Download className="w-3.5 h-3.5" /> Export
             </Button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-sm text-left">
              <thead className="bg-muted text-muted-foreground text-xs uppercase tracking-wider">
                <tr>
                  <th className="px-4 py-3">Category</th>
                  <th className="px-4 py-3 text-center">Items</th>
                  <th className="px-4 py-3 text-right">Total Cost</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {categoryStats.map(c => (
                  <tr key={c.cat} className="hover:bg-muted/50 transition-colors">
                    <td className="px-4 py-3 font-medium text-foreground">{c.cat}</td>
                    <td className="px-4 py-3 text-center text-muted-foreground">{c.items}</td>
                    <td className="px-4 py-3 text-right font-bold text-foreground">AED {c.cost.toLocaleString(undefined, {minimumFractionDigits:2})}</td>
                  </tr>
                ))}
                {categoryStats.length === 0 && <tr><td colSpan="3" className="p-4 text-center text-muted-foreground bg-background">No purchase data.</td></tr>}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
}

import React, { useMemo, useState } from 'react';
import { useStockReport } from '@/lib/queries';
import { DataTable } from '@/components/shared/DataTable';
import { StatusBadge } from '@/components/shared/StatusBadge';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Button } from '@/components/ui/button';
import { AlertCircle, TrendingUp, CheckCircle2, Download } from 'lucide-react';
import { exportCSV } from '@/lib/utils';
import { cn } from '@/lib/utils';

export function StockLevelsTab() {
  const { data: stockData = [], isLoading } = useStockReport();
  
  const [location, setLocation] = useState('all');
  const [category, setCategory] = useState('all');
  const [status, setStatus] = useState('all');

  const locations = useMemo(() => [...new Set(stockData.map(s => s.location_name).filter(Boolean))], [stockData]);
  const categories = useMemo(() => [...new Set(stockData.map(s => s.category).filter(Boolean))], [stockData]);

  const filtered = useMemo(() => {
    return stockData.filter(s => {
      if (location !== 'all' && s.location_name !== location) return false;
      if (category !== 'all' && s.category !== category) return false;
      
      const avail = s.available || 0;
      const sStat = avail === 0 ? 'out' : (avail <= (s.min_stock_level || 0) && s.min_stock_level > 0 ? 'low' : 'ok');
      if (status !== 'all' && sStat !== status) return false;
      
      return true;
    });
  }, [stockData, location, category, status]);

  const outOfStock = filtered.filter(s => (s.available || 0) === 0).length;
  const lowStock = filtered.filter(s => (s.available || 0) > 0 && (s.available || 0) <= (s.min_stock_level || 0) && s.min_stock_level > 0).length;
  const okStock = filtered.filter(s => (s.available || 0) > (s.min_stock_level || 0) || ((s.available || 0) > 0 && !(s.min_stock_level > 0))).length;

  const handleExport = () => {
    exportCSV('stock_levels_report', filtered);
  };

  const columns = [
    { header: "SKU", key: "sku", render: (r) => <span className="font-mono text-xs bg-slate-100 px-1.5 py-0.5 rounded border border-border text-muted-foreground">{r.sku}</span> },
    { header: "Tool Name", key: "name", render: (r) => <span className="font-medium">{r.name}</span> },
    { header: "Category", key: "category", render: (r) => <span className="text-muted-foreground text-sm">{r.category}</span> },
    { header: "Location", key: "location_name", render: (r) => <span className="text-muted-foreground text-sm">{r.location_name}</span> },
    { header: "Total", key: "total", render: (r) => <span className="text-muted-foreground">{r.total}</span> },
    { header: "Reserved", key: "reserved", render: (r) => <span className="text-muted-foreground">{r.reserved}</span> },
    { header: "Available", key: "available", render: (r) => {
        const avail = r.available || 0;
        return <span className={cn("font-bold text-base", avail === 0 ? "text-red-600" : (avail <= (r.min_stock_level || 0) && r.min_stock_level > 0 ? "text-amber-600" : "text-green-600"))}>{avail}</span>
    }},
    { header: "Min Level", key: "min_stock_level", render: (r) => <span className="text-slate-400">{r.min_stock_level || 0}</span> },
    { header: "Status", key: "status", render: (r) => {
        const avail = r.available || 0;
        const s = avail === 0 ? 'out' : (avail <= (r.min_stock_level || 0) && r.min_stock_level > 0 ? 'low' : 'ok');
        return <StatusBadge type="stock" status={s} />
    }},
    { header: "Last Movement", key: "last_movement", render: (r) => <span className="text-xs text-muted-foreground">{r.last_movement ? new Date(r.last_movement).toLocaleDateString() : '-'}</span> }
  ];

  return (
    <div className="space-y-4 animate-in fade-in">
      <div className="flex flex-col md:flex-row justify-between gap-4">
         <div className="flex flex-wrap items-center gap-3">
            <Select value={location} onValueChange={setLocation}>
              <SelectTrigger className="w-[180px]"><SelectValue placeholder="Location" /></SelectTrigger>
              <SelectContent className="z-50">
                <SelectItem value="all">All Locations</SelectItem>
                {locations.map(l => <SelectItem key={l} value={l}>{l}</SelectItem>)}
              </SelectContent>
            </Select>
            <Select value={category} onValueChange={setCategory}>
              <SelectTrigger className="w-[180px]"><SelectValue placeholder="Category" /></SelectTrigger>
              <SelectContent className="z-50">
                <SelectItem value="all">All Categories</SelectItem>
                {categories.map(c => <SelectItem key={c} value={c}>{c}</SelectItem>)}
              </SelectContent>
            </Select>
            <Select value={status} onValueChange={setStatus}>
              <SelectTrigger className="w-[180px]"><SelectValue placeholder="Status" /></SelectTrigger>
              <SelectContent className="z-50">
                <SelectItem value="all">All Statuses</SelectItem>
                <SelectItem value="ok">In Stock (OK)</SelectItem>
                <SelectItem value="low">Low Stock</SelectItem>
                <SelectItem value="out">Out of Stock</SelectItem>
              </SelectContent>
            </Select>
         </div>
         <Button onClick={handleExport} variant="outline" className="gap-2 bg-background">
           <Download className="w-4 h-4" /> Export CSV
         </Button>
      </div>

      <div className="flex gap-4">
         <div className="flex items-center gap-2 px-3 py-1.5 bg-red-50 text-red-700 rounded-lg border border-red-200 text-sm font-medium">
            <AlertCircle className="w-4 h-4" /> {outOfStock} out of stock
         </div>
         <div className="flex items-center gap-2 px-3 py-1.5 bg-amber-50 text-amber-700 rounded-lg border border-amber-200 text-sm font-medium">
            <TrendingUp className="w-4 h-4" /> {lowStock} low stock
         </div>
         <div className="flex items-center gap-2 px-3 py-1.5 bg-green-50 text-green-700 rounded-lg border border-green-200 text-sm font-medium">
            <CheckCircle2 className="w-4 h-4" /> {okStock} ok
         </div>
      </div>

      <div className="bg-background rounded-xl shadow-sm border border-border overflow-hidden">
        <DataTable columns={columns} data={filtered} isLoading={isLoading} searchKeys={["sku", "name", "category"]} emptyMessage="No stock data found." />
      </div>
    </div>
  );
}

import React, { useState, useMemo } from 'react';
import { useTransfersReport } from '@/lib/queries';
import { DataTable } from '@/components/shared/DataTable';
import { StatusBadge } from '@/components/shared/StatusBadge';
import { Input } from '@/components/ui/input';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Button } from '@/components/ui/button';
import { Download, ArrowRight } from 'lucide-react';
import { exportCSV } from '@/lib/utils';

export function TransfersTab() {
  const [dateFrom, setDateFrom] = useState(() => {
    const d = new Date(); d.setDate(d.getDate() - 90); return d.toISOString().split('T')[0];
  });
  const [dateTo, setDateTo] = useState(() => new Date().toISOString().split('T')[0]);

  const { data: transfers = [], isLoading } = useTransfersReport({
    startDate: new Date(dateFrom).getTime(),
    endDate: new Date(dateTo).getTime() + 86400000
  });

  const [statusFilter, setStatusFilter] = useState('all');
  const [fromLocation, setFromLocation] = useState('all');
  const [toLocation, setToLocation] = useState('all');

  const fromLocations = useMemo(() => [...new Set(transfers.map(t => t.from_location).filter(Boolean))], [transfers]);
  const toLocations = useMemo(() => [...new Set(transfers.map(t => t.to_location).filter(Boolean))], [transfers]);

  const filtered = useMemo(() => {
    return transfers.filter(t => {
      if (statusFilter !== 'all' && t.status !== statusFilter) return false;
      if (fromLocation !== 'all' && t.from_location !== fromLocation) return false;
      if (toLocation !== 'all' && t.to_location !== toLocation) return false;
      return true;
    });
  }, [transfers, statusFilter, fromLocation, toLocation]);

  const handleExport = () => exportCSV('transfers_report', filtered);

  // Summaries
  const pending = filtered.filter(t => t.status === 'draft' || t.status === 'approved').length;
  const completed = filtered.filter(t => t.status === 'completed').length;
  const cancelled = filtered.filter(t => t.status === 'cancelled').length;

  const routesMap = {};
  const toolMap = {};
  filtered.forEach(t => {
    const route = `${t.from_location} ΓåÆ ${t.to_location}`;
    routesMap[route] = (routesMap[route] || 0) + 1;
    toolMap[t.tool_name] = (toolMap[t.tool_name] || 0) + 1;
  });
  const topRoute = Object.entries(routesMap).sort((a,b) => b[1] - a[1])[0];
  const topTool = Object.entries(toolMap).sort((a,b) => b[1] - a[1])[0];

  const columns = [
    { header: "Tool", key: "tool_name", render: (t) => (
      <div className="flex flex-col">
        <span className="font-medium text-foreground">{t.tool_name}</span>
        <span className="text-[10px] font-mono text-muted-foreground">{t.sku}</span>
      </div>
    )},
    { header: "Qty", key: "quantity", render: (t) => <span className="font-bold">{t.quantity}</span> },
    { header: "From", key: "from_location", render: (t) => <span className="text-sm font-medium text-amber-700">{t.from_location}</span> },
    { header: "To", key: "to_location", render: (t) => <span className="text-sm font-medium text-indigo-700">{t.to_location}</span> },
    { header: "Status", key: "status", render: (t) => <StatusBadge type="transfer" status={t.status} /> },
    { header: "Requested By", key: "requested_by", render: (t) => <span className="text-xs text-muted-foreground">{t.requested_by}</span> },
    { header: "Requested Date", key: "requested_date", render: (t) => <span className="text-sm">{new Date(t.requested_date).toLocaleDateString()}</span> },
    { header: "Completed Date", key: "completed_at", render: (t) => (
      <span className="text-sm">{t.completed_at ? new Date(t.completed_at).toLocaleDateString() : '-'}</span>
    )}
  ];

  return (
    <div className="space-y-6 animate-in fade-in">
      <div className="grid grid-cols-2 lg:grid-cols-6 gap-4 p-4 bg-muted rounded-xl border border-border">
        <div className="flex flex-col"><span className="text-xs font-medium text-muted-foreground uppercase">Total Transfers</span><span className="text-2xl font-bold">{filtered.length}</span></div>
        <div className="flex flex-col"><span className="text-xs font-medium text-muted-foreground uppercase">Pending</span><span className="text-2xl font-bold text-amber-600">{pending}</span></div>
        <div className="flex flex-col"><span className="text-xs font-medium text-muted-foreground uppercase">Completed</span><span className="text-2xl font-bold text-green-600">{completed}</span></div>
        <div className="flex flex-col"><span className="text-xs font-medium text-muted-foreground uppercase">Cancelled</span><span className="text-2xl font-bold text-red-600">{cancelled}</span></div>
        <div className="flex flex-col truncate" title={topTool ? topTool[0] : '-'}><span className="text-xs font-medium text-muted-foreground uppercase">Top Tool Moved</span><span className="text-sm font-bold truncate mt-1">{topTool ? topTool[0] : '-'}</span></div>
        <div className="flex flex-col truncate" title={topRoute ? topRoute[0] : '-'}><span className="text-xs font-medium text-muted-foreground uppercase">Top Route</span><span className="text-sm font-bold truncate mt-1">{topRoute ? topRoute[0] : '-'}</span></div>
      </div>

      <div className="flex flex-col lg:flex-row justify-between gap-4">
        <div className="flex flex-wrap items-center gap-3">
          <div className="flex items-center gap-2">
             <Input type="date" value={dateFrom} onChange={e => setDateFrom(e.target.value)} className="w-[140px]" />
             <span className="text-muted-foreground">ΓåÆ</span>
             <Input type="date" value={dateTo} onChange={e => setDateTo(e.target.value)} className="w-[140px]" />
          </div>
          <Select value={statusFilter} onValueChange={setStatusFilter}>
            <SelectTrigger className="w-[150px]"><SelectValue placeholder="Status" /></SelectTrigger>
            <SelectContent className="z-50">
              <SelectItem value="all">All Statuses</SelectItem>
              <SelectItem value="draft">Draft / Pend</SelectItem>
              <SelectItem value="approved">Approved</SelectItem>
              <SelectItem value="completed">Completed</SelectItem>
              <SelectItem value="cancelled">Cancelled</SelectItem>
            </SelectContent>
          </Select>
          <div className="flex items-center gap-2 bg-background border border-border rounded-lg pl-3 pr-1 py-1">
             <span className="text-xs text-muted-foreground uppercase font-bold tracking-wider">Route:</span>
             <Select value={fromLocation} onValueChange={setFromLocation}>
               <SelectTrigger className="w-[130px] border-none shadow-none h-8"><SelectValue placeholder="From Loc" /></SelectTrigger>
               <SelectContent className="z-50 border-border">
                 <SelectItem value="all">Any Origin</SelectItem>
                 {fromLocations.map(l => <SelectItem key={l} value={l}>{l}</SelectItem>)}
               </SelectContent>
             </Select>
             <ArrowRight className="w-3 h-3 text-muted-foreground" />
             <Select value={toLocation} onValueChange={setToLocation}>
               <SelectTrigger className="w-[130px] border-none shadow-none h-8"><SelectValue placeholder="To Loc" /></SelectTrigger>
               <SelectContent className="z-50 border-border">
                 <SelectItem value="all">Any Dest</SelectItem>
                 {toLocations.map(l => <SelectItem key={l} value={l}>{l}</SelectItem>)}
               </SelectContent>
             </Select>
          </div>
        </div>
        <Button onClick={handleExport} variant="outline" className="gap-2 bg-background">
          <Download className="w-4 h-4" /> Export CSV
        </Button>
      </div>

      <div className="bg-background rounded-xl shadow-sm border border-border overflow-hidden">
        <DataTable columns={columns} data={filtered} isLoading={isLoading} searchKeys={["tool_name", "sku", "requested_by"]} emptyMessage="No transfers found." />
      </div>
    </div>
  );
}

import React, { useState, useMemo } from 'react';
import { useWorkerHoldings } from '@/lib/queries';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Input } from '@/components/ui/input';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { ChevronDown, ChevronRight, Download } from 'lucide-react';
import { ReturnToolModal } from '@/components/lending/ReturnToolModal';
import { exportCSV, cn } from '@/lib/utils';

export function WorkerHoldingsTab() {
  const { data: res, isLoading } = useWorkerHoldings();
  const holdings = res?.workers || [];
  
  const [expanded, setExpanded] = useState(new Set());
  const [returnLoan, setReturnLoan] = useState(null);
  
  // Filters
  const [search, setSearch] = useState('');
  const [company, setCompany] = useState('all');
  const [statusFilter, setStatusFilter] = useState('all');

  const companies = useMemo(() => [...new Set(holdings.map(w => w.company).filter(c => c && c.trim() !== ''))], [holdings]);

  const filtered = useMemo(() => {
    return holdings.filter(w => {
      // Search by name
      if (search && !(w.name || '').toLowerCase().includes(search.toLowerCase())) return false;
      // Filter by company
      if (company !== 'all' && w.company !== company) return false;
      // Filter by status (has overdue / no items)
      if (statusFilter === 'overdue' && (w.overdue_count || 0) === 0) return false;
      if (statusFilter === 'no_items' && (w.active_loan_count || 0) > 0) return false;
      if (statusFilter === 'has_items' && (w.active_loan_count || 0) === 0) return false;
      
      return true;
    });
  }, [holdings, search, company, statusFilter]);

  const handleExport = () => {
    exportCSV('worker_holdings_report', filtered.map(w => ({
      WorkerName: w.name,
      Phone: w.phone || '',
      Company: w.company || '',
      ActiveItems: w.active_loan_count || 0,
      OverdueCount: w.overdue_count || 0,
      ReliabilityScore: w.total_loans && w.total_loans > 0 ? Math.round((w.on_time_returns / w.total_loans) * 100) : 'N/A'
    })));
  };

  // SummaryStats
  const totalWorkersActive = holdings.filter(w => (w.active_loan_count || 0) > 0).length;
  const totalItemsOnLoan = holdings.reduce((acc, w) => acc + (w.active_loan_count || 0), 0);
  const totalOverdue = holdings.reduce((acc, w) => acc + (w.overdue_count || 0), 0);
  const avgItems = totalWorkersActive > 0 ? (totalItemsOnLoan / totalWorkersActive).toFixed(1) : 0;

  if (isLoading) return <div className="p-8 text-center text-muted-foreground animate-pulse">Loading holdings...</div>;

  return (
    <div className="space-y-6 animate-in fade-in">
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4 p-4 bg-muted rounded-xl border border-border">
        <div className="flex flex-col">
          <span className="text-sm font-medium text-muted-foreground">Workers w/ Active Loans</span>
          <span className="text-2xl font-bold text-foreground">{totalWorkersActive}</span>
        </div>
        <div className="flex flex-col">
          <span className="text-sm font-medium text-muted-foreground">Total Items on Loan</span>
          <span className="text-2xl font-bold text-foreground">{totalItemsOnLoan}</span>
        </div>
        <div className="flex flex-col">
          <span className="text-sm font-medium text-muted-foreground">Total Overdue Items</span>
          <span className="text-2xl font-bold text-red-600">{totalOverdue}</span>
        </div>
        <div className="flex flex-col">
          <span className="text-sm font-medium text-muted-foreground">Avg Items / Worker</span>
          <span className="text-2xl font-bold text-foreground">{avgItems}</span>
        </div>
      </div>

      <div className="flex flex-col md:flex-row justify-between gap-4">
        <div className="flex flex-wrap items-center gap-3 flex-1">
          <Input 
            type="search" 
            placeholder="Search workers..." 
            value={search} 
            onChange={(e) => setSearch(e.target.value)}
            className="w-[200px]"
          />
          <Select value={company} onValueChange={setCompany}>
            <SelectTrigger className="w-[180px]"><SelectValue placeholder="Company" /></SelectTrigger>
            <SelectContent className="z-50">
              <SelectItem value="all">All Companies</SelectItem>
              {companies.map(c => <SelectItem key={c} value={c}>{c}</SelectItem>)}
            </SelectContent>
          </Select>
          <Select value={statusFilter} onValueChange={setStatusFilter}>
            <SelectTrigger className="w-[200px]"><SelectValue placeholder="Filter By" /></SelectTrigger>
            <SelectContent className="z-50">
              <SelectItem value="all">All Workers</SelectItem>
              <SelectItem value="has_items">Has Active Items</SelectItem>
              <SelectItem value="no_items">No Items Currently</SelectItem>
              <SelectItem value="overdue">Has Overdue Items</SelectItem>
            </SelectContent>
          </Select>
        </div>
        <Button onClick={handleExport} variant="outline" className="gap-2 bg-background">
          <Download className="w-4 h-4" /> Export CSV
        </Button>
      </div>

      <div className="space-y-3">
        {filtered.length === 0 ? (
          <div className="text-center p-12 bg-background rounded-xl border border-border text-muted-foreground">No workers found matching filters.</div>
        ) : (
          filtered.map(worker => {
            const isExp = expanded.has(worker.id);
            const totalReturns = worker.total_loans || 0;
            const onTime = worker.on_time_returns || 0;
            const relScore = totalReturns > 0 ? Math.round((onTime / totalReturns) * 100) : null;
            const displayRel = relScore !== null ? `${relScore}%` : 'No returns yet';

            return (
              <div key={worker.id} className="bg-background rounded-xl shadow-sm border border-border overflow-hidden">
                <div 
                  className={cn("p-4 flex items-center justify-between cursor-pointer hover:bg-muted transition-colors", isExp ? "bg-muted border-b border-border" : "")}
                  onClick={() => {
                    const next = new Set(expanded);
                    if (next.has(worker.id)) next.delete(worker.id);
                    else next.add(worker.id);
                    setExpanded(next);
                  }}
                >
                  <div className="flex flex-col sm:flex-row sm:items-center gap-2 sm:gap-6">
                    <div className="flex flex-col">
                      <span className="font-bold text-foreground text-lg">{worker.name}</span>
                      <span className="text-sm text-muted-foreground">{worker.phone ? worker.phone : 'No phone'} {worker.company ? `┬╖ ${worker.company}` : ''}</span>
                    </div>
                    <div className="flex items-center gap-3">
                      <Badge className="bg-blue-100 text-blue-800 hover:bg-blue-100 font-bold px-2 py-1">{(worker.active_loan_count || 0)} Items</Badge>
                      {(worker.overdue_count || 0) > 0 && (
                        <Badge className="bg-red-100 text-red-800 hover:bg-red-100 font-bold px-2 py-1">{(worker.overdue_count)} Overdue</Badge>
                      )}
                      <Badge variant="outline" className="bg-slate-50 text-slate-700 border-slate-200 uppercase text-[10px] font-bold">Rel: {displayRel}</Badge>
                    </div>
                  </div>
                  <div className="text-slate-400">
                    {isExp ? <ChevronDown className="w-5 h-5" /> : <ChevronRight className="w-5 h-5" />}
                  </div>
                </div>

                {isExp && (
                  <div className="p-0 bg-card overflow-x-auto">
                     <table className="w-full text-sm text-left">
                       <thead className="bg-muted text-muted-foreground text-xs uppercase tracking-wider">
                         <tr>
                           <th className="px-6 py-2">Item</th>
                           <th className="px-6 py-2">Date Out</th>
                           <th className="px-6 py-2">Due Date</th>
                           <th className="px-6 py-2">Status</th>
                           <th className="px-6 py-2 text-right">Actions</th>
                         </tr>
                       </thead>
                       <tbody className="divide-y divide-border">
                         {(worker.loans || []).map(loan => {
                           const overdue = loan.expected_return_date && new Date(loan.expected_return_date).getTime() < Date.now();
                           const daysOut = Math.floor((Date.now() - new Date(loan.date_out).getTime()) / 86400000);
                           
                           return (
                             <tr key={loan.id} className="hover:bg-muted/50 transition-colors">
                               <td className="px-6 py-3">
                                 <div className="flex items-center gap-2">
                                   <span className="font-mono text-[10px] bg-background border border-border px-1 py-0.5 rounded text-muted-foreground">{loan.sku}</span>
                                   <span className="font-medium text-foreground">{loan.tool_name}</span>
                                 </div>
                               </td>
                               <td className="px-6 py-3 text-muted-foreground">{new Date(loan.date_out).toLocaleDateString()}</td>
                               <td className="px-6 py-3">
                                  {loan.expected_return_date ? new Date(loan.expected_return_date).toLocaleDateString() : 'No Due Date'}
                               </td>
                               <td className="px-6 py-3">
                                  {overdue ? (
                                    <span className="uppercase text-[10px] font-bold bg-red-100 text-red-700 px-2 py-1 rounded">Overdue ({daysOut}d)</span>
                                  ) : (
                                    <span className="uppercase text-[10px] font-bold bg-green-100 text-green-700 px-2 py-1 rounded">Active ({daysOut}d)</span>
                                  )}
                               </td>
                               <td className="px-6 py-3 text-right">
                                  <Button size="sm" variant="outline" onClick={() => setReturnLoan(loan)}>Return</Button>
                               </td>
                             </tr>
                           )
                         })}
                         {(worker.loans || []).length === 0 && (
                           <tr><td colSpan="5" className="p-4 text-center text-muted-foreground bg-background">No active items for this worker.</td></tr>
                         )}
                       </tbody>
                     </table>
                  </div>
                )}
              </div>
            )
          })
        )}
      </div>
      <ReturnToolModal isOpen={!!returnLoan} onClose={() => setReturnLoan(null)} loan={returnLoan} />
    </div>
  );
}
